INSERT INTO questions (level, question, option1, option2, option3, option4, correct_answer, explanation) VALUES
(4, 'What is digital forensics?', 'Repairing damaged hard drives', 'The process of collecting and analyzing digital evidence for investigations', 'Designing secure digital systems', 'Monitoring network traffic in real time', 'The process of collecting and analyzing digital evidence for investigations', 'Digital forensics involves identifying, preserving, analyzing, and presenting digital evidence from computers, networks, and storage devices. It is used in criminal investigations, incident response, and legal proceedings. Chain of custody is critical to ensure evidence integrity.'),
(4, 'What does chain of custody mean in digital forensics?', 'A blockchain-based security protocol', 'The documented process of handling evidence to maintain its integrity', 'A method to chain multiple encryption keys', 'A network topology used in forensic labs', 'The documented process of handling evidence to maintain its integrity', 'Chain of custody documents every person who handled the evidence, when, and why. This ensures the evidence has not been tampered with and is admissible in court. Breaking the chain of custody can invalidate evidence in legal proceedings.'),
(4, 'What is an Indicator of Compromise (IoC)?', 'A certificate proving a system is secure', 'Forensic evidence that a system may have been breached', 'A compliance checklist for security audits', 'A type of intrusion prevention rule', 'Forensic evidence that a system may have been breached', 'IoCs are artifacts observed on a network or system that indicate a potential intrusion. Examples include unusual outbound traffic, known malicious IP addresses, unexpected registry changes, or suspicious file hashes. Security teams use IoCs to detect and respond to breaches.'),
(4, 'What is the first step in incident response?', 'Eradication', 'Recovery', 'Identification and Detection', 'Lessons learned', 'Identification and Detection', 'The NIST incident response lifecycle has four phases: Preparation, Detection and Analysis, Containment/Eradication/Recovery, and Post-Incident Activity. Detection is the first active phase where you identify that an incident has occurred using alerts, logs, and user reports.'),
(4, 'What is memory forensics?', 'Analyzing the physical memory chips of a computer', 'Extracting and analyzing data from a computer RAM', 'Recovering deleted files from a hard drive', 'Scanning memory for malware signatures only', 'Extracting and analyzing data from a computer RAM', 'Memory forensics involves capturing and analyzing the volatile memory of a running system. It can reveal running processes, network connections, encryption keys, passwords, and malware that may not exist on disk. Tools like Volatility are commonly used.'),
(4, 'What is log analysis in cybersecurity?', 'Deleting old system logs to free space', 'Reviewing system and network logs to detect suspicious activity', 'Compressing log files for storage', 'Encrypting log files to prevent tampering', 'Reviewing system and network logs to detect suspicious activity', 'Log analysis involves examining records generated by systems, applications, and network devices to identify anomalies, security events, and attack patterns. Centralized log management with SIEM tools enables correlation of events across multiple sources for faster threat detection.'),
(4, 'What is a forensic image?', 'A screenshot taken during an investigation', 'A bit-for-bit copy of a storage device used for analysis', 'A photo of physical evidence at a crime scene', 'A compressed backup of important files', 'A bit-for-bit copy of a storage device used for analysis', 'A forensic image is an exact sector-by-sector copy of a storage device, including deleted files and unallocated space. Analysis is performed on the image rather than the original to preserve evidence integrity. Tools like dd, FTK Imager, and EnCase are commonly used.'),
(4, 'What does DFIR stand for?', 'Digital Firewall and Intrusion Response', 'Digital Forensics and Incident Response', 'Data Forensics and Information Recovery', 'Distributed Forensics and Intelligence Reporting', 'Digital Forensics and Incident Response', 'DFIR combines digital forensics with incident response. DFIR teams investigate breaches, determine root causes, assess damage, and help organizations recover while preserving evidence for legal proceedings.'),
(4, 'What is steganography?', 'A method of encrypting network traffic', 'Hiding secret data within ordinary files like images or audio', 'A technique for cracking encrypted passwords', 'A type of network scanning tool', 'Hiding secret data within ordinary files like images or audio', 'Steganography is the practice of concealing information within non-secret data to avoid detection. Unlike encryption which makes data unreadable, steganography hides the existence of the message. It can be used by attackers to exfiltrate data or communicate covertly.'),
(4, 'What is the purpose of a honeypot in cybersecurity?', 'To store sensitive data securely', 'A decoy system designed to attract and study attackers', 'To speed up network performance', 'A tool for encrypting communications', 'A decoy system designed to attract and study attackers', 'A honeypot is a security resource designed to be probed, attacked, or compromised. It lures attackers away from real systems, allows security teams to study attack techniques, and provides early warning of intrusions. Honeynets are networks of multiple honeypots.');
INSERT INTO questions (level, question, option1, option2, option3, option4, correct_answer, explanation) VALUES
(5, 'What is the shared responsibility model in cloud security?', 'Cloud providers are responsible for all security', 'Customers are responsible for all security', 'Security responsibilities are divided between the cloud provider and the customer', 'A third-party auditor handles all security responsibilities', 'Security responsibilities are divided between the cloud provider and the customer', 'In the shared responsibility model, the cloud provider secures the underlying infrastructure while the customer is responsible for securing their data, applications, identity management, and configurations. The exact split varies by service type: IaaS, PaaS, or SaaS.'),
(5, 'What is a container escape attack?', 'Exiting a Docker container normally', 'An attack where malicious code breaks out of a container to access the host system', 'Migrating containers between cloud providers', 'Removing unused containers from a system', 'An attack where malicious code breaks out of a container to access the host system', 'Container escape attacks exploit vulnerabilities in container runtimes like Docker or misconfigurations to break out of the isolated container environment and gain access to the host OS or other containers. Prevention includes using minimal base images and running containers as non-root.'),
(5, 'What is DevSecOps?', 'A team of developers who also handle security operations', 'Integrating security practices throughout the DevOps pipeline', 'A security framework for legacy systems', 'A tool for scanning source code', 'Integrating security practices throughout the DevOps pipeline', 'DevSecOps integrates security into every phase of the software development lifecycle from design and coding to testing and deployment. It shifts security left earlier in the process, automates security testing in CI/CD pipelines, and makes security a shared responsibility across teams.'),
(5, 'What is a JWT (JSON Web Token)?', 'A type of database query language', 'A compact self-contained token for securely transmitting information between parties', 'A JavaScript testing framework', 'A web server configuration format', 'A compact self-contained token for securely transmitting information between parties', 'JWTs are used for authentication and information exchange. They consist of three parts: Header (algorithm), Payload (claims/data), and Signature (verification). The signature ensures the token has not been tampered with. JWTs should be stored securely and have short expiration times.'),
(5, 'What is Infrastructure as Code (IaC) security?', 'Writing code to build physical infrastructure', 'Securing cloud infrastructure defined through code like Terraform or CloudFormation', 'A programming language for network devices', 'Encrypting source code repositories', 'Securing cloud infrastructure defined through code like Terraform or CloudFormation', 'IaC security involves scanning infrastructure definition files like Terraform and CloudFormation for misconfigurations before deployment. Common issues include overly permissive IAM roles, open security groups, and unencrypted storage. Tools like Checkov and tfsec help enforce security policies.'),
(5, 'What is a side-channel attack?', 'An attack through a secondary network interface', 'Exploiting information leaked by the physical implementation of a system', 'Attacking backup systems instead of primary ones', 'A social engineering attack via phone calls', 'Exploiting information leaked by the physical implementation of a system', 'Side-channel attacks extract secret information by analyzing physical characteristics of a system such as timing, power consumption, or electromagnetic emissions rather than exploiting software vulnerabilities. Spectre and Meltdown are famous examples that exploited CPU timing side channels.'),
(5, 'What is OAuth 2.0?', 'A password hashing algorithm', 'An authorization framework allowing third-party apps limited access to user accounts', 'A two-factor authentication standard', 'A network encryption protocol', 'An authorization framework allowing third-party apps limited access to user accounts', 'OAuth 2.0 enables applications to obtain limited access to user accounts on third-party services without exposing passwords. It uses access tokens instead of credentials. Common flows include Authorization Code for web apps and Client Credentials for server-to-server communication.'),
(5, 'What is threat modeling?', 'Creating 3D models of cyber threats for visualization', 'A structured process to identify, prioritize, and mitigate security threats', 'Predicting future malware trends using AI', 'Building a database of known threat actors', 'A structured process to identify, prioritize, and mitigate security threats', 'Threat modeling is a proactive security practice where teams systematically identify potential threats and vulnerabilities in a system during the design phase. The STRIDE framework covers Spoofing, Tampering, Repudiation, Information Disclosure, Denial of Service, and Elevation of Privilege.'),
(5, 'What is a WAF (Web Application Firewall)?', 'A firewall that only works on wireless networks', 'A security tool that filters and monitors HTTP traffic to protect web applications', 'A tool for accelerating web application performance', 'A framework for building secure web applications', 'A security tool that filters and monitors HTTP traffic to protect web applications', 'A WAF sits between web clients and web servers, inspecting HTTP/HTTPS traffic to detect and block attacks like SQL injection, XSS, and CSRF. Unlike network firewalls that operate at the network layer, WAFs understand application-layer protocols and content.'),
(5, 'What is the concept of Zero Trust security?', 'Trusting no vendors for security products', 'Never trust always verify with no implicit trust for any user or device', 'A security model with zero configuration required', 'Removing all trust certificates from a network', 'Never trust always verify with no implicit trust for any user or device', 'Zero Trust is a security model based on never trust, always verify. It assumes threats exist both inside and outside the network, so every access request must be authenticated, authorized, and continuously validated regardless of location. Key components include identity verification and micro-segmentation.');
